import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";
import Peer from "simple-peer";

const socket = io("http://localhost:3001");

function App() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const [stream, setStream] = useState(null);
  const myVideo = useRef();
  const userVideo = useRef();
  const connectionRef = useRef();

  useEffect(() => {
    socket.on("chat message", (msg) => {
      setChat((prevChat) => [...prevChat, msg]);
    });

    socket.on("call-user", (signal) => {
      const peer = new Peer({ initiator: false, trickle: false, stream });
      peer.on("signal", (data) => {
        socket.emit("call-user", data);
      });
      peer.on("stream", (remoteStream) => {
        userVideo.current.srcObject = remoteStream;
      });
      peer.signal(signal);
      connectionRef.current = peer;
    });
  }, [stream]);

  const sendMessage = (e) => {
    e.preventDefault();
    socket.emit("chat message", message);
    setMessage("");
  };

  // Audio-only call
  const startAudioCall = () => {
    navigator.mediaDevices.getUserMedia({ audio: true }).then((currentStream) => {
      setStream(currentStream);

      const peer = new Peer({ initiator: true, trickle: false, stream: currentStream });
      peer.on("signal", (data) => {
        socket.emit("call-user", data);
      });
      peer.on("stream", (remoteStream) => {
        userVideo.current.srcObject = remoteStream;
      });
      connectionRef.current = peer;
    });
  };

  // Video + audio call
  const startVideoCall = () => {
    navigator.mediaDevices.getUserMedia({ video: true, audio: true }).then((currentStream) => {
      setStream(currentStream);
      myVideo.current.srcObject = currentStream;

      const peer = new Peer({ initiator: true, trickle: false, stream: currentStream });
      peer.on("signal", (data) => {
        socket.emit("call-user", data);
      });
      peer.on("stream", (remoteStream) => {
        userVideo.current.srcObject = remoteStream;
      });
      connectionRef.current = peer;
    });
  };

  // End call
  const hangUp = () => {
    if (connectionRef.current) {
      connectionRef.current.destroy();
    }
    if (myVideo.current) {
      myVideo.current.srcObject = null;
    }
    if (userVideo.current) {
      userVideo.current.srcObject = null;
    }
    setStream(null);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "20px" }}>
      <h2>💬 Chat + 🎙️ Audio + 📹 Video</h2>

      {/* Chat Box */}
      <div style={{ border: "1px solid #ccc", width: "400px", height: "200px", margin: "auto", overflowY: "scroll", padding: "10px" }}>
        {chat.map((msg, index) => (
          <p key={index}>{msg}</p>
        ))}
      </div>
      <form onSubmit={sendMessage} style={{ marginTop: "10px" }}>
        <input
          type="text"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Type a message..."
          style={{ width: "300px", padding: "10px" }}
        />
        <button type="submit" style={{ padding: "10px 20px", marginLeft: "10px" }}>Send</button>
      </form>

      {/* Call Buttons */}
      <div style={{ marginTop: "20px" }}>
        <button onClick={startAudioCall} style={{ padding: "10px 20px", marginRight: "10px" }}>
          Start Audio Call 🎙️
        </button>
        <button onClick={startVideoCall} style={{ padding: "10px 20px", marginRight: "10px" }}>
          Start Video Call 📹
        </button>
        <button onClick={hangUp} style={{ padding: "10px 20px", backgroundColor: "red", color: "white" }}>
          Hang Up ❌
        </button>
      </div>

      {/* Video Windows */}
      <div style={{ display: "flex", justifyContent: "center", marginTop: "20px" }}>
        <video playsInline muted ref={myVideo} autoPlay style={{ width: "300px", marginRight: "20px" }} />
        <video playsInline ref={userVideo} autoPlay style={{ width: "300px" }} />
      </div>
    </div>
  );
}

export default App;
